import AppKit
import Combine

struct NewClipData {
    let type: ClipType
    let text: String?
    let imageData: Data?
    let filePath: String?
    let appBundleID: String?
    let appName: String?
}

// Types UTI à ignorer (mots de passe, données temporaires, artefacts système)
private let passwordIndicatorTypes: Set<String> = [
    "org.nspasteboard.ConcealedType",
    "org.nspasteboard.TransientType",
    "org.nspasteboard.AutoGeneratedType",
    "com.agilebits.onepassword",
    "com.1password.item-data",
    "RoboFormData",
    "com.lastpass.lpdefaulttype"
]

final class ClipboardMonitor {
    var onNewItem: ((NewClipData) -> Void)?

    private var timer: Timer?
    private var lastChangeCount: Int

    init() {
        lastChangeCount = NSPasteboard.general.changeCount
    }

    func start() {
        timer = Timer.scheduledTimer(withTimeInterval: 0.5, repeats: true) { [weak self] _ in
            self?.checkPasteboard()
        }
        RunLoop.main.add(timer!, forMode: .common)
    }

    func stop() {
        timer?.invalidate()
        timer = nil
    }

    private func checkPasteboard() {
        let pasteboard = NSPasteboard.general
        guard pasteboard.changeCount != lastChangeCount else { return }
        lastChangeCount = pasteboard.changeCount

        let sourceApp = NSWorkspace.shared.frontmostApplication
        let bundleID = sourceApp?.bundleIdentifier ?? ""

        guard bundleID != Bundle.main.bundleIdentifier else { return }

        // Lire les apps ignorées depuis UserDefaults (toujours à jour)
        let ignored = Set(UserDefaults.standard.stringArray(forKey: "ignoredBundleIDs") ?? [])
        guard !ignored.contains(bundleID) else { return }

        extractContent(from: pasteboard, appBundleID: bundleID, appName: sourceApp?.localizedName)
    }

    private func extractContent(from pasteboard: NSPasteboard, appBundleID: String, appName: String?) {
        guard let items = pasteboard.pasteboardItems, !items.isEmpty else { return }

        // Ignorer les mots de passe si le réglage est actif (activé par défaut)
        let ignorePasswords = UserDefaults.standard.bool(forKey: "ignorePasswords")
        if ignorePasswords {
            for item in items {
                for type in item.types where passwordIndicatorTypes.contains(type.rawValue) {
                    return
                }
            }
        }

        // Image
        if let tiff = pasteboard.data(forType: .tiff) {
            onNewItem?(.init(type: .image, text: nil, imageData: tiff, filePath: nil, appBundleID: appBundleID, appName: appName))
            return
        }
        if let png = pasteboard.data(forType: .png) {
            onNewItem?(.init(type: .image, text: nil, imageData: png, filePath: nil, appBundleID: appBundleID, appName: appName))
            return
        }

        // Fichiers
        if let urls = pasteboard.readObjects(forClasses: [NSURL.self], options: [.urlReadingFileURLsOnly: true]) as? [URL],
           let first = urls.first {
            let path = first.path
            onNewItem?(.init(type: .file, text: path, imageData: nil, filePath: path, appBundleID: appBundleID, appName: appName))
            return
        }

        // Texte
        if let text = pasteboard.string(forType: .string) {
            let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { return }
            let isURL = URL(string: text)?.scheme?.hasPrefix("http") == true
            onNewItem?(.init(type: isURL ? .url : .text, text: text, imageData: nil, filePath: nil, appBundleID: appBundleID, appName: appName))
        }
    }
}
